using System;
using System.Diagnostics;

public class PdfGenerator
{
    public void GeneratePdf(string htmlPath, string pdfPath, PageSize pageSize = PageSize.A4, Orientation orientation = Orientation.Portrait)
    {
        var options = $"--page-size {pageSize} --orientation {orientation}";
        var command = $"wkhtmltopdf {options} \"{htmlPath}\" \"{pdfPath}\"";

        using (var process = new Process())
        {
            process.StartInfo.FileName = "cmd.exe";
            process.StartInfo.Arguments = "/c start /wait wkhtmltopdf.exe";
            process.StartInfo.UseShellExecute = false;
            process.StartInfo.RedirectStandardInput = true;
            process.Start();

            process.StandardInput.WriteLine(command);
            process.StandardInput.Close();
        }
    }

    public enum PageSize
    {
        A4,
        Letter
    }

    public enum Orientation
    {
        Portrait,
        Landscape
    }
}